#[tokio::test]
async fn test_ocr_multi_page() {
    // OCR request returning multiple pages of document content
    let mock_route = MockRoute {
        path: "/ocr",
        method: "POST",
        status: 200,
        body: r##"{"model":"mistral/mistral-ocr-latest","pages":[{"index":0,"markdown":"# Page 1\n\nThis is the first page of the document."},{"index":1,"markdown":"# Page 2\n\nThis is the second page of the document."}]}"##.to_string(),
        is_streaming: false,
        stream_chunks: vec![],
        headers: vec![
        ],
        delay_ms: None,
    };
    let mock_server = MockServer::start(vec![mock_route]).await;
    let request_json = serde_json::json!({"document": {"type": "document_url", "url": "https://example.com/multipage.pdf"}, "model": "mistral/mistral-ocr-latest"});
    let request = serde_json::from_value(request_json).unwrap();
    let client =
        liter_llm::create_client("test-key".to_string(), Some(mock_server.url.clone()), None, None, None).unwrap();
    let result = client.ocr(request).await.expect("should succeed");
    assert_eq!(
        result.pages.len(),
        2,
        "expected exactly 2 elements, got {}",
        result.pages.len()
    );
    assert_eq!(result.pages[0].index, 0, "equals assertion failed");
    assert_eq!(result.pages[1].index, 1, "equals assertion failed");
}

